#include<bits/stdc++.h>
#define ll long long
#define CI const int
#define PII pair<int,int>
using namespace std;
CI MAXN=4e5+5;
stack<int> st;
int n,a[MAXN]; 
int main(void){
	scanf("%d",&n);
	for(int i=1,u,v;i<=n;++i)
	{
		scanf("%d%d",&u,&v);
		a[u]=v;
		a[v]=u;
	}
	for(int i=1;i<=2*n;++i)
	{
		if(st.size()&&st.top()==a[i])st.pop();
		else st.push(i);
	}
	printf("%s",((st.empty())?("No"):("Yes")));
	return false;
}
